import axios from "axios";

const api = axios.create({
  baseURL: import.meta.env.REACT_APP_API_URL || "http://localhost:5000/api",
  timeout: 30000,
});

let getToken = () => "";
let onTokenRefresh = async () => null;

export function configureApi({ tokenGetter, refreshHandler }) {
  getToken = tokenGetter;
  onTokenRefresh = refreshHandler;
}

api.interceptors.request.use((config) => {
  const token = getToken();
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

api.interceptors.response.use(
  (response) => response,
  async (error) => {
    if (error?.response?.status === 401 && !error.config.__retried) {
      error.config.__retried = true;
      const nextToken = await onTokenRefresh();
      if (nextToken) {
        error.config.headers.Authorization = `Bearer ${nextToken}`;
        return api.request(error.config);
      }
    }
    return Promise.reject(error);
  }
);

export default api;
